// 收外部請求 → 組 Telegram 通知文 + Webhook 回應
const headers = $input.first().json.headers || {};
const query = $input.first().json.query || {};
const ip = headers['cf-connecting-ip'] || headers['x-forwarded-for'] || 'unknown';
const ua = headers['user-agent'] || 'unknown';
const ts = new Date().toLocaleString('zh-TW');

const tgMsg = `📡 外部 ping 收到！\n\n⏰ ${ts}\n🌐 IP: ${ip}\n🤖 User-Agent: ${ua.substring(0, 80)}\n📦 Query: ${JSON.stringify(query)}\n\n（你的本機 n8n 正在被外部觸發！）`;

return [{
  json: {
    tgMsg,
    response: {
      status: 'ok',
      message: 'pong from your local n8n via cloudflare tunnel',
      receivedAt: ts,
      from: ip
    }
  }
}];
